def fibonacci(n):
    if n <= 0:
        return 0
    elif n == 1:
        return 1
    else:
        return fibonacci(n-1) + fibonacci(n-2)

# 或者使用迭代方式
def fibonacci_iter(n):
    if n <= 0:
        return 0
    a, b = 0, 1
    for _ in range(n - 1):
        a, b = b, a + b
    return b

递归函数是指在函数定义中调用自身的函数。递归包含两个关键部分：
1. 基准情况（Base Case）：停止递归的条件
2. 递归情况（Recursive Case）：函数调用自身的逻辑

示例：计算阶乘
def factorial(n):
    # 基准情况
    if n == 0 or n == 1:
        return 1
    # 递归情况
    else:
        return n * factorial(n - 1)

# 使用示例
print(factorial(5))  # 输出: 120
